// handleUpsert updates the policy count when a CiliumNetworkPolicy is created or updated.
func (c *PolicyQuotaController) handleUpsert(cnp *cilium_v2.CiliumNetworkPolicy) {
	namespace := cnp.Namespace
	name := cnp.Name
	policyKey := namespace + "/" + name

	c.mu.Lock()
	defer c.mu.Unlock()

	// Check if this is a new policy
	if !c.seenPolicies[policyKey] {
		c.seenPolicies[policyKey] = true
		c.namespacePolicyCounts[namespace]++

		c.log.WithFields(logrus.Fields{
			logfields.K8sNamespace:            namespace,
			logfields.CiliumNetworkPolicyName: name,
			"policy_count":                    c.namespacePolicyCounts[namespace],
		}).Debug("CiliumNetworkPolicy created")
	} else {
		c.log.WithFields(logrus.Fields{
			logfields.K8sNamespace:            namespace,
			logfields.CiliumNetworkPolicyName: name,
		}).Debug("CiliumNetworkPolicy updated")
	}
}

