// handleDelete decrements the policy count when a CiliumNetworkPolicy is deleted.
func (c *PolicyQuotaController) handleDelete(cnp *cilium_v2.CiliumNetworkPolicy) {
	namespace := cnp.Namespace
	name := cnp.Name

	c.mu.Lock()
	defer c.mu.Unlock()

	if count, ok := c.namespacePolicyCounts[namespace]; ok && count > 0 {
		count--
		if count == 0 {
			delete(c.namespacePolicyCounts, namespace)
		} else {
			c.namespacePolicyCounts[namespace] = count
		}

		c.log.WithFields(logrus.Fields{
			logfields.K8sNamespace:            namespace,
			logfields.CiliumNetworkPolicyName: name,
			"remaining_policies":              count,
		}).Debug("CiliumNetworkPolicy deleted")
	}
}

