func TestHandleUpsert(t *testing.T) {
	logger := logrus.New()
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(logger, mockResource, 10)

